var maximumEnergy = function(energy, k) {
    const n = energy.length;
    const suffix = energy.slice();
    for (let i = n - 1; i >= 0; i--) {
        if (i + k < n) suffix[i] += suffix[i + k];
    }
    return Math.max(...suffix);
};
